window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["h"]={"Henryk": "<b>Henryk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „potężny”, „możny” lub „bogaty”. Wśród imion nadawanych nowo narodzonym dzieciom, Henryk w 2017 r. zajmował 77. miejsce w grupie imion męskich. W całej populacji Polaków w 2017 r. Henryk zajmował 30. miejsce (207 913 nadań).", "Hubert": "<b>Hubert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Tłumaczy się jako «człowiek wyróżniający się <a href=\"https://pl.wikipedia.org/wiki/Rozum\" target=\"_blank\" rel=\"noopener noreferrer\">rozumem</a>» (człon <i>hugu</i> oznacza «umysł, rozum», natomiast <i>beraht</i> – «sławny»).", "Hieronim": "<b>Hieronim</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słów oznaczających „święte imię” (<i>ἱερός, dor. τὸ ὄνυμα + ος</i>).", "Herbert": "<b>Herbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, <i>Herbert</i>. Wywodzi się od słowa oznaczającego „błyszczący”, „jaśniejący”. Patronem tego imienia jest św. Herbert, pustelnik z <a href=\"https://pl.wikipedia.org/wiki/Cumberland_(hrabstwo_w_Anglii)\" target=\"_blank\" rel=\"noopener noreferrer\">Cumberland</a> wspominany <a href=\"https://pl.wikipedia.org/wiki/20_marca\" target=\"_blank\" rel=\"noopener noreferrer\">20 marca</a>.", "Hugo": "<b>Hugo</b>, <b>Hugon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które powstało przez skrócenie germańskich imion ze składnikiem <i>hugu</i> (<a href=\"https://pl.wikipedia.org/wiki/Rozum\" target=\"_blank\" rel=\"noopener noreferrer\">rozum</a>, umysł), co oznacza \"człowiek rozumny, bystry\".", "Helmut": "Wywodzi się od słów <i>heil</i> i <i>muot</i> oznaczających kolejno „zdrowy, cały” i \"„męstwo, duch, <a href=\"https://pl.wikipedia.org/wiki/Rozum\" target=\"_blank\" rel=\"noopener noreferrer\">rozum</a>”.", "Herman": "<b>Herman</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „wojownik”. Innym jego wariantem jest <b><a href=\"https://pl.wikipedia.org/wiki/Armin\" target=\"_blank\" rel=\"noopener noreferrer\">Armin</a></b>, natomiast nazwisko <a href=\"https://pl.wikipedia.org/wiki/Menzel\" target=\"_blank\" rel=\"noopener noreferrer\">Menzel</a> stanowi podwójne zdrobnienie imienia Hermann. W średniowiecznej Polsce odnotowywano polskie formy Jerzman i Jirzman.", "Horst": "Imię to pochodzi z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">języka średnio-wysoko-niemieckiego</a>, w którym wyraz brzmiący <i>hurst</i> (<a href=\"https://pl.wikipedia.org/wiki/Liczba_mnoga\" target=\"_blank\" rel=\"noopener noreferrer\">liczba mnoga</a> <i>hürste</i>) miał znaczenie „krzewy, krzaki, zarośla, gąszcz, gęstwina”. Pierwotnie zatem imię to mogło znaczyć „człowiek z lasu”.", "Hilary": "<b>Hilary</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> <i>laris</i>, z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> <i>larós</i> – wesoły, pogodny, radosny) – imię męskie pochodzenia łacińsko-greckiego. Od tego imienia powstała staropolska forma skrócona (zdrobniała, spieszczona) <i><b>Larysz</b></i>, utworzona za pomocą popularnej w imiennictwie polskim, a także ruskim techniki ucinania nagłosu.", "Hipolit": "<b>Hipolit</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od słowa <i>Hippólytos</i> oznaczającego „powozić koniem”, „mający rozpędzone konie”.", "Harald": "<b>Harald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia staroangielskiego/nordyckiego.", "Hamza": "<b>Hamza</b> (<b>ء</b>) – znak <a href=\"https://pl.wikipedia.org/wiki/Alfabet_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">pisma arabskiego</a>, reprezentujący <a href=\"https://pl.wikipedia.org/wiki/Zwarcie_krtaniowe\" target=\"_blank\" rel=\"noopener noreferrer\">zwarcie krtaniowe</a> (<a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">IPA</a> [<a href=\"https://pl.wikipedia.org/wiki/Zwarcie_krtaniowe\" target=\"_blank\" rel=\"noopener noreferrer\">ʔ</a>]). Hamza nie jest uznawana za literę i istnieje ze względu na niejasności w zapisie pewnych wyrazów, powstałe w czasach wczesnego <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islamu</a>. W <a href=\"https://pl.wikipedia.org/wiki/Alfabet_aramejski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabecie aramejskim</a> i <a href=\"https://pl.wikipedia.org/wiki/Alfabet_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskim</a> zwarcie krtaniowe jest oznaczane literą <i><a href=\"https://pl.wikipedia.org/wiki/Alef\" target=\"_blank\" rel=\"noopener noreferrer\">alef</a></i>, odpowiednikiem arabskiego <i>ʼ<a href=\"https://pl.wikipedia.org/wiki/Alif\" target=\"_blank\" rel=\"noopener noreferrer\">alifa</a></i>, który jednak oznacza głównie samogłoskę [<a href=\"https://pl.wikipedia.org/wiki/Samog%C5%82oska_otwarta_przednia_niezaokr%C4%85glona\" target=\"_blank\" rel=\"noopener noreferrer\">a</a><a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99dzynarodowy_alfabet_fonetyczny\" target=\"_blank\" rel=\"noopener noreferrer\">&#58;</a>]. Pierwotnie, hamza była znakiem diakrytycznym odróżniającym dwie wartości fonetyczne alifa (podobnie jak kreska nad polskim <i>ć</i>).", "Hugon": "<b>Hugo</b>, <b>Hugon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które powstało przez skrócenie germańskich imion ze składnikiem <i>hugu</i> (<a href=\"https://pl.wikipedia.org/wiki/Rozum\" target=\"_blank\" rel=\"noopener noreferrer\">rozum</a>, umysł), co oznacza \"człowiek rozumny, bystry\".", "Heliodor": "<b>Heliodor</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Stanowi złożenie słów <i>Helios</i> – „słońce” i <i>dōron</i> – „dar”, a oznacza „dar słońca” lub „dar <a href=\"https://pl.wikipedia.org/wiki/Helios_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Heliosa</a>” (w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> boga-słońca). Nadawane w Polsce co najmniej od <a href=\"https://pl.wikipedia.org/wiki/1746\" target=\"_blank\" rel=\"noopener noreferrer\">1746</a> roku.", "Horacy": "<b>Horacy</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a> nazwy rodowej <em>Horatius</em>, której pochodzenie jest niejasne, przedłacińskie. Imię to występowało w Polsce już w średniowieczu, m.in. w formach <i>Horacy</i>, <i>Oracy</i>, a także <i>Jaracz</i>, <i>Jeracz</i>.", "Honoriusz": "<b>Honoriusz</b>, <b>Honory</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od wyrazu pospolitego <i>honor</i>, co oznacza 'cześć, godność, honor'.", "Honorat": "<b>Honorat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa <i>honoratus</i>, oznaczającego „szanowany, darzony szacunkiem”. Patronami imienia są m.in. św. <a href=\"https://pl.wikipedia.org/wiki/Honorat_z_Arles\" target=\"_blank\" rel=\"noopener noreferrer\">Honorat z Arles</a> i bł. <a href=\"https://pl.wikipedia.org/wiki/Honorat_Ko%C5%BAmi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Honorat Koźmiński</a>.", "Hani": "Uważa się, że Hani wywodzą się od <a href=\"https://pl.wikipedia.org/wiki/Qiang\" target=\"_blank\" rel=\"noopener noreferrer\">Qiangów</a> i ok. III wieku przybyli do Chin z <a href=\"https://pl.wikipedia.org/wiki/Wy%C5%BCyna_Tybeta%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Wyżyny Tybetańskiej</a>. Sami Hani uważają się jednak za potomków <a href=\"https://pl.wikipedia.org/wiki/Yi_(grupa_etniczna)\" target=\"_blank\" rel=\"noopener noreferrer\">Yi</a>, od których mieli się oddzielić 50 pokoleń temu.", "Hiroshi": "<b>Hiroshi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひろし, ヒロシ) – popularne męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Hafiz": "W religioznawstwie oznacza także honorowy tytuł nadawany osobom, które nauczyły się <i><a href=\"https://pl.wikipedia.org/wiki/Koran\" target=\"_blank\" rel=\"noopener noreferrer\">Koranu</a></i> na pamięć i strzegą go w pamięci.", "Ha": "Nazwa pochodzi od przedrostka „<a href=\"https://pl.wikipedia.org/wiki/Hekto\" target=\"_blank\" rel=\"noopener noreferrer\">hekto-</a>” oznaczającego 100 i nazwy jednostki miary „<a href=\"https://pl.wikipedia.org/wiki/Ar_(jednostka_miary)\" target=\"_blank\" rel=\"noopener noreferrer\">ar</a>”.", "Hui": "<b>Hui</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chiń.</a> 回族&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a> <i>Huízú</i>, <a href=\"https://pl.wikipedia.org/wiki/Xiao%E2%80%99erjing\" target=\"_blank\" rel=\"noopener noreferrer\">xiao’erjing</a>: خُوِذُو / حواري, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_dunga%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">dungański</a>: Хуэйзў/Huejzw) – jedna z 55 uznanych oficjalnie <a href=\"https://pl.wikipedia.org/wiki/Mniejszo%C5%9Bci_narodowe_w_Chi%C5%84skiej_Republice_Ludowej\" target=\"_blank\" rel=\"noopener noreferrer\">mniejszości w Chińskiej Republice Ludowej</a>. Nazwa Hui oznacza zasadniczo „muzułmanin mieszkający w Chinach”. Zamieszkują całą <a href=\"https://pl.wikipedia.org/wiki/Chi%C5%84ska_Republika_Ludowa\" target=\"_blank\" rel=\"noopener noreferrer\">Chińską Republikę Ludową</a> (szczególnie <a href=\"https://pl.wikipedia.org/wiki/Gansu\" target=\"_blank\" rel=\"noopener noreferrer\">Gansu</a>, <a href=\"https://pl.wikipedia.org/wiki/Henan\" target=\"_blank\" rel=\"noopener noreferrer\">Henan</a>, <a href=\"https://pl.wikipedia.org/wiki/Sinciang\" target=\"_blank\" rel=\"noopener noreferrer\">Ujgurski Region Autonomiczny Xinjiang</a>, <a href=\"https://pl.wikipedia.org/wiki/Qinghai\" target=\"_blank\" rel=\"noopener noreferrer\">Qinghai</a>, <a href=\"https://pl.wikipedia.org/wiki/Junnan\" target=\"_blank\" rel=\"noopener noreferrer\">Yunnan</a>, <a href=\"https://pl.wikipedia.org/wiki/Szantung\" target=\"_blank\" rel=\"noopener noreferrer\">Shandong</a>), a największe skupisko znajduje się w południowym obszarze <a href=\"https://pl.wikipedia.org/wiki/Ningxia\" target=\"_blank\" rel=\"noopener noreferrer\">Regionu Autonomicznego Ningxia</a> (1/3 regionu jest zamieszkiwana przez Hui). Grupa ta ze względu na język oraz cechy kulturowe jest podobna do Chińczyków Han, wyróżnik stanowi jedynie religia – zdecydowana większość wyznaje <a href=\"https://pl.wikipedia.org/wiki/Islam\" target=\"_blank\" rel=\"noopener noreferrer\">islam</a>, co pociąga za sobą inne różnice.", "Hiacynt": "<b>Hiacynt</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od imienia <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitycznego</a> <a href=\"https://pl.wikipedia.org/wiki/Hiacynt_(syn_Amyklasa)\" target=\"_blank\" rel=\"noopener noreferrer\">Hyakinthosa</a>, syna Amyklasa i Diomedy. Z jego krwi wyrosły kwiaty nazwane od jego imienia – hiacynty (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>hiacynthus</em>). Z kolei od Hyakinthosa pochodzi imię Hiacynt. Imię to uległo spolszczeniu do form: <a href=\"https://pl.wikipedia.org/wiki/Jacek\" target=\"_blank\" rel=\"noopener noreferrer\">Jacenty</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Jacek\" target=\"_blank\" rel=\"noopener noreferrer\">Jacek</a>.", "Hugues": "<b>Hugo</b>, <b>Hugon</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, które powstało przez skrócenie germańskich imion ze składnikiem <i>hugu</i> (<a href=\"https://pl.wikipedia.org/wiki/Rozum\" target=\"_blank\" rel=\"noopener noreferrer\">rozum</a>, umysł), co oznacza \"człowiek rozumny, bystry\".", "Hoa": "<b>Hoa</b> – <a href=\"https://pl.wikipedia.org/wiki/Mniejszo%C5%9B%C4%87_etniczna\" target=\"_blank\" rel=\"noopener noreferrer\">mniejszość etniczna</a> w <a href=\"https://pl.wikipedia.org/wiki/Wietnam\" target=\"_blank\" rel=\"noopener noreferrer\">Wietnamie</a> pochodzenia chińskiego (<a href=\"https://pl.wikipedia.org/wiki/Chi%C5%84czycy_Han\" target=\"_blank\" rel=\"noopener noreferrer\">Chińczycy Han</a>). Mieszkają głównie w miastach na południu Wietnamu, stąd bywają określani jako <i>miejscy Chińczycy</i>. Ich przodkami byli uchodźcy przybywający do <a href=\"https://pl.wikipedia.org/wiki/Indochiny\" target=\"_blank\" rel=\"noopener noreferrer\">Indochin</a> za czasów panowania <a href=\"https://pl.wikipedia.org/wiki/Dynastia_Qing\" target=\"_blank\" rel=\"noopener noreferrer\">dynastii Qing</a>, począwszy od drugiej połowy XVII w. W czasach kolonialnych skupiali w swoich rękach większość handlu, transportu i przedsiębiorstw. Według spisu z 1999 liczba ludności Hoa wynosiła w Wietnamie 862 371 osób. Ta liczba systematycznie się zmniejsza wskutek emigracji oraz polityki asymilacyjnej, będącej wynikiem podpisanej w 1955 umowy między Chinami i Wietnamem.", "Halit": "<b>Halit</b> – <a href=\"https://pl.wikipedia.org/wiki/Minera%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">minerał</a> z gromady <a href=\"https://pl.wikipedia.org/wiki/Halogenki\" target=\"_blank\" rel=\"noopener noreferrer\">halogenków</a>. Nazwa pochodzi od greckich słów ἅλς <i>hals</i> – sól, oraz λίθος <i>lithos</i> – kamień. Minerał znany i używany od czasów starożytnych. Głównym składnikiem jest <a href=\"https://pl.wikipedia.org/wiki/Chlorek_sodu\" target=\"_blank\" rel=\"noopener noreferrer\">chlorek sodu</a>.", "Herkules": "Rzymska <a href=\"https://pl.wikipedia.org/wiki/Legenda\" target=\"_blank\" rel=\"noopener noreferrer\">legenda</a> przypisuje Herkulesowi zabicie olbrzyma <a href=\"https://pl.wikipedia.org/wiki/Kakus\" target=\"_blank\" rel=\"noopener noreferrer\">Kakusa</a> i króla <a href=\"https://pl.wikipedia.org/wiki/Faun\" target=\"_blank\" rel=\"noopener noreferrer\">Faunusa</a>. Herkulesa miał w swoim kraju ugościć <a href=\"https://pl.wikipedia.org/wiki/Ewander\" target=\"_blank\" rel=\"noopener noreferrer\">Ewander</a>, zaś po śmierci herosa ustanowił jego kult. Początkowo Herkules był czczony w <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymie</a> jako opiekun własności, strażnik wejść i opiekun podróżujących oraz handlujących. Rolnicy i kupcy składali mu dziesięcinę z zysków i zbiorów. W IV wieku p.n.e. Herkules stał się bogiem zwycięstwa i nadano mu przydomki <i>Victor</i> (Zwycięzca) i <i>Invictus</i> (Niezwyciężony). Młodzi żołnierze rzymscy czcili go jako najpotężniejszego i niezwyciężonego herosa a wodzowie i triumfatorzy prosili go o pomoc w zwycięstwie i oddawali mu część łupów wojennych. Atrybutem Herkulesa, inaczej niż jego greckiego odpowiednika, była <a href=\"https://pl.wikipedia.org/wiki/Lira\" target=\"_blank\" rel=\"noopener noreferrer\">lira</a>. Przedstawiany był z nią często w towarzystwie <a href=\"https://pl.wikipedia.org/wiki/Apollo\" target=\"_blank\" rel=\"noopener noreferrer\">Apollona</a> i <a href=\"https://pl.wikipedia.org/wiki/Muzy\" target=\"_blank\" rel=\"noopener noreferrer\">muz</a>. W dniu 12 sierpnia przypadało w Rzymie <a href=\"https://pl.wikipedia.org/wiki/%C5%9Awi%C4%99to_Herkulesa\" target=\"_blank\" rel=\"noopener noreferrer\">święto Herkulesa</a>, natomiast 4 czerwca obchodzono święto Herkulesa Wielkiego Opiekuna (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Hercules Magnus Custos</em>).", "Hanna": "<b>Anna</b>, <b>Hanna</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;חַנָּה&#8206; <i>hannāh</i> – „łaska”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>, które tłumaczy się jako „pełna wdzięku, łaski”.", "Hiroki": "<b>Hiroki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひろき, ヒロキ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Hideki": "<b>Hideki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひでき, ヒデキ) – popularne męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Homer": "Najstarszy znany z imienia europejski poeta, który zapewne przejął dziedzictwo długiej i bogatej tradycji ustnej poezji heroicznej. Do jego dzieł zalicza się eposy: <i><a href=\"https://pl.wikipedia.org/wiki/Iliada\" target=\"_blank\" rel=\"noopener noreferrer\">Iliadę</a></i> i <i><a href=\"https://pl.wikipedia.org/wiki/Odyseja\" target=\"_blank\" rel=\"noopener noreferrer\">Odyseję</a></i>. Grecka tradycja widziała w nim również autora zbioru hymnów, tzw. <a href=\"https://pl.wikipedia.org/wiki/Hymny_homeryckie\" target=\"_blank\" rel=\"noopener noreferrer\">hymnów homeryckich</a>, oraz kilku <a href=\"https://pl.wikipedia.org/wiki/Poemat_heroikomiczny\" target=\"_blank\" rel=\"noopener noreferrer\">poematów heroikomicznych</a> – <i><a href=\"https://pl.wikipedia.org/wiki/Margites\" target=\"_blank\" rel=\"noopener noreferrer\">Margites</a></i> (<i>Głuptak</i>), Kerkopes (<i>Kerkopowie</i>), Epikichlides (<i>Chichotki</i>), <i><a href=\"https://pl.wikipedia.org/wiki/Batrachomyomachia\" target=\"_blank\" rel=\"noopener noreferrer\">Batrachomyomachia</a></i> (<i>Wojna mysio-żabia</i>). Żaden poeta grecki nie przewyższył sławą Homera. Na wyspach <a href=\"https://pl.wikipedia.org/wiki/Ios\" target=\"_blank\" rel=\"noopener noreferrer\">Ios</a> i <a href=\"https://pl.wikipedia.org/wiki/Chios\" target=\"_blank\" rel=\"noopener noreferrer\">Chios</a> wzniesiono poświęcone mu świątynie, a w <a href=\"https://pl.wikipedia.org/wiki/Olimpia\" target=\"_blank\" rel=\"noopener noreferrer\">Olimpii</a> i <a href=\"https://pl.wikipedia.org/wiki/Delfy\" target=\"_blank\" rel=\"noopener noreferrer\">Delfach</a> postawiono jego posągi. <a href=\"https://pl.wikipedia.org/wiki/Pizystrat\" target=\"_blank\" rel=\"noopener noreferrer\">Pizystrat</a> wprowadził recytacje homeryckich poematów na <a href=\"https://pl.wikipedia.org/wiki/Panatenaje\" target=\"_blank\" rel=\"noopener noreferrer\">Panatenajach</a>.", "Haruki": "<b>Haruki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;はるき, ハルキ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Hayato": "<b>Hayato</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;はやと, ハヤト) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Heribert": "<b>Herybert</b> – oboczna forma męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Herbert\" target=\"_blank\" rel=\"noopener noreferrer\">Herbert</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">niem.</a> <i>Heribert</i>, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hiszpa%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">hiszp.</a> <i>Heriberto</i>. Wywodzi się od słowa oznaczającego \"błyszczący\", \"jaśniejący\".Nie należy łączyć obu tych imion.", "Hitoshi": "<b>Hitoshi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひとし, ヒトシ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">męskie imię japońskie</a>.", "Herakliusz": "<b>Herakliusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzące od greckiego imienia <a href=\"https://pl.wikipedia.org/wiki/Herakles_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Herakles</a>, oznaczające <i>poświęcony Heraklesowi, należący do Heraklesa</i>.", "Haruto": "<b>Haruto</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;はると, ハルト) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Hideo": "<b>Hideo</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひでお, ヒデオ) – popularne męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Hygin": "<b>Hygin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Imię wywodzi się od słowa <i>hygieinos</i> oznaczającego \"zdrowy\".", "Hikaru": "<b>Hikaru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひかる, ヒカル) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety i mężczyzn.", "Hào": "<b>Hao</b> (od chińskiego 毫, <i>dziesiąta część</i>) – <a href=\"https://pl.wikipedia.org/wiki/Moneta_zdawkowa\" target=\"_blank\" rel=\"noopener noreferrer\">moneta zdawkowa</a> formalnie stosowana w <a href=\"https://pl.wikipedia.org/wiki/Wietnam\" target=\"_blank\" rel=\"noopener noreferrer\">Wietnamie</a> jako równowartość 1/10 <a href=\"https://pl.wikipedia.org/wiki/%C4%90%E1%BB%93ng\" target=\"_blank\" rel=\"noopener noreferrer\">donga</a> i 10 <a href=\"https://pl.wikipedia.org/wiki/Xu\" target=\"_blank\" rel=\"noopener noreferrer\">xu</a>. Obecnie ze względu na inflację nie występuje już w obiegu, a najmniejszym nominałem wietnamskiej waluty jest banknot o wartości 100 dongów.", "Hiram": "<b>Hiram</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a>.", "Heron": "<b>Heron</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> wywodzące się od wyrazu pospolitego <i>hērōs</i>, co oznacza „mocny, silny, bohater”, przejęte do łaciny jako <i>Ero</i> // <i>Hero</i> // <i>Heron</i>.", "Hyo": "<b>Nabożność synowska</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chiń.</a>&#160;孝, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#160;こう, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">kor.</a>&#160;효) – jedna z najważniejszych cnót w <a href=\"https://pl.wikipedia.org/wiki/Konfucjanizm\" target=\"_blank\" rel=\"noopener noreferrer\">konfucjanizmie</a> oraz innych dalekowschodnich systemach <a href=\"https://pl.wikipedia.org/wiki/Etyka\" target=\"_blank\" rel=\"noopener noreferrer\">etycznych</a>. Jej chińskiej nazwy, <i>xiao</i>, często się nie tłumaczy, bo oznacza ona: <i>miłość, szacunek i posłuszeństwo wobec rodziców, przodków i krewnych</i>. Mimo ogromnych przemian społecznych w <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX wieku</a>, nabożność synowska jest jedną z wartości wysoko cenionych w <a href=\"https://pl.wikipedia.org/wiki/Chi%C5%84ska_Republika_Ludowa\" target=\"_blank\" rel=\"noopener noreferrer\">Chinach</a>, całej <a href=\"https://pl.wikipedia.org/wiki/Korea\" target=\"_blank\" rel=\"noopener noreferrer\">Korei</a>, <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonii</a>, <a href=\"https://pl.wikipedia.org/wiki/Wietnam\" target=\"_blank\" rel=\"noopener noreferrer\">Wietnamie</a>, a także na <a href=\"https://pl.wikipedia.org/wiki/Republika_Chi%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Tajwanie</a> i w <a href=\"https://pl.wikipedia.org/wiki/Singapur\" target=\"_blank\" rel=\"noopener noreferrer\">Singapurze</a>.", "Horacjusz": "<b>Horacjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu.", "Honory": "<b>Honoriusz</b>, <b>Honory</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od wyrazu pospolitego <i>honor</i>, co oznacza 'cześć, godność, honor'.", "Hilarion": "<b>Hilarion</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od greckiego ‘ιλαρος (<i>hilaros</i>) oznaczającego \"pogodny\", \"radosny\". Było to imię świętego z <a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku</a>. Wersje ruskie to Ilarion (Иларион) i Larion (Ларион).", "Hermenegild": "<b>Hermenegild</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia germańskiego.", "Haru": "<b>Haru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;はる, ハル) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety jak i przez mężczyzn.", "Hajime": "<b>Hajime</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;はじめ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Hallel": "Psalmy te rozpoczynają się słowami: <i><a href=\"https://pl.wikipedia.org/wiki/Alleluja\" target=\"_blank\" rel=\"noopener noreferrer\">Alleluja</a>. Chwalcie słudzy <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, chwalcie imię Jahwe: Niech imię Jahwe będzie błogosławione odtąd i aż na wieki.</i>, a kończą słowami: <i>Wysławiajcie Jahwe, bo dobry; bo łaska Jego na wieki!</i>", "Hermogenes": "<b>Hermogenes</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, zapisywane <i>‘Ερμογενης</i>. Oznacza „urodzony z <a href=\"https://pl.wikipedia.org/wiki/Hermes\" target=\"_blank\" rel=\"noopener noreferrer\">Hermesa</a>” (od imienia Hermes oraz słowa γενης <i>genes</i> „urodzony”). Imię to nosił <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII-wieczny</a> święty pochodzący z Rosji <a href=\"https://pl.wikipedia.org/wiki/Hermogen_(patriarcha_Moskwy)\" target=\"_blank\" rel=\"noopener noreferrer\">Hermogen, patriarcha Moskwy</a> i inni święci.", "Haruna": "<b>Haruna</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;はるな, ハルナ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Hideaki": "<b>Hideaki</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひであき, ヒデアキ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Herc": "Nazwa jednostki pochodzi od nazwiska niemieckiego fizyka <a href=\"https://pl.wikipedia.org/wiki/Heinrich_Hertz\" target=\"_blank\" rel=\"noopener noreferrer\">Heinricha Hertza</a>, zajmującego się m.in. badaniem <a href=\"https://pl.wikipedia.org/wiki/Promieniowanie_elektromagnetyczne\" target=\"_blank\" rel=\"noopener noreferrer\">fal elektromagnetycznych</a>.", "Hinata": "<b>Hinata</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひなた, ヒナタ) – głównie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>, rzadko noszone przez mężczyzn, jest też używane jako nazwisko.", "Hongqi": "<b>Hongqi</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chiń.</a>&#160;红旗) – luksusowa marka samochodów. 红旗 (Hongqi) oznacza <a href=\"https://pl.wikipedia.org/wiki/Czerwony_sztandar_(flaga)\" target=\"_blank\" rel=\"noopener noreferrer\">czerwoną flagę</a> (zasadniczo w znaczeniu czerwonego sztandaru), jest to charakterystyczny znaczek tego pojazdu.", "Herold": "W <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytna_Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">starożytnej Grecji</a> urzędnikiem o podobnym charakterze lecz z większym zakresem zadań był <a href=\"https://pl.wikipedia.org/wiki/Keryks\" target=\"_blank\" rel=\"noopener noreferrer\">keryks</a>. Słowo \"herold\" wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_starogerma%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">starogermańskiego</a> słowa <i>hariowaldus</i>, tj. ten, który zna się, rozpoznaje opiekuńcze bóstwa rodowe, plemienne oraz zna ich rodowody.", "Herakles": "<b>Herakles</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a> Ἡρακλῆς, <a href=\"https://pl.wikipedia.org/wiki/Transliteracja\" target=\"_blank\" rel=\"noopener noreferrer\">trl.</a> Hēraklēs, gr. Ἡρακλέης, trl. Hērakléēs, <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Hercules</em>), Alkides, Palajmon – w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a> jeden z <a href=\"https://pl.wikipedia.org/wiki/Heros\" target=\"_blank\" rel=\"noopener noreferrer\">herosów</a>, syn <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a> i śmiertelniczki <a href=\"https://pl.wikipedia.org/wiki/Alkmena\" target=\"_blank\" rel=\"noopener noreferrer\">Alkmeny</a>. Jego <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskim</a> odpowiednikiem był <a href=\"https://pl.wikipedia.org/wiki/Herkules\" target=\"_blank\" rel=\"noopener noreferrer\">Herkules</a>. Znany był z wielkiej siły, waleczności, męstwa, zapaśnictwa i umiejętności wojennych, zwłaszcza celnego strzelania z łuku. Lubiany przez Zeusa i <a href=\"https://pl.wikipedia.org/wiki/Atena\" target=\"_blank\" rel=\"noopener noreferrer\">Atenę</a>, był prześladowany przez zazdrosną <a href=\"https://pl.wikipedia.org/wiki/Hera\" target=\"_blank\" rel=\"noopener noreferrer\">Herę</a>. Żonaty z <a href=\"https://pl.wikipedia.org/wiki/Megara_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Megarą</a>, <a href=\"https://pl.wikipedia.org/wiki/Dejanira\" target=\"_blank\" rel=\"noopener noreferrer\">Dejanirą</a> i <a href=\"https://pl.wikipedia.org/wiki/Hebe_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Hebe</a>.", "Hanafi": "<b>Hanafici</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a>&#160;&#8207;حنفي&#8206;) – zwolennicy jednej z czterech głównych <a href=\"https://pl.wikipedia.org/wiki/Sunnizm\" target=\"_blank\" rel=\"noopener noreferrer\">sunnickich</a> <a href=\"https://pl.wikipedia.org/wiki/Mazhab\" target=\"_blank\" rel=\"noopener noreferrer\">szkół</a> <a href=\"https://pl.wikipedia.org/wiki/Szariat\" target=\"_blank\" rel=\"noopener noreferrer\">prawa muzułmańskiego</a>, wywodzącej się od teologa <a href=\"https://pl.wikipedia.org/wiki/Abu_Hanifa\" target=\"_blank\" rel=\"noopener noreferrer\">Abu Hanify</a> (zm. 767).", "Hammam": "<a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">Arabski</a> gramatyk <a href=\"https://pl.wikipedia.org/wiki/Ibn_Sida\" target=\"_blank\" rel=\"noopener noreferrer\">Ibn Sida</a> wywodzi nazwę od słowa <i>al-ḥamīm</i> (\"siła letniego gorąca\").", "Halel": "Psalmy te rozpoczynają się słowami: <i><a href=\"https://pl.wikipedia.org/wiki/Alleluja\" target=\"_blank\" rel=\"noopener noreferrer\">Alleluja</a>. Chwalcie słudzy <a href=\"https://pl.wikipedia.org/wiki/Jahwe\" target=\"_blank\" rel=\"noopener noreferrer\">Jahwe</a>, chwalcie imię Jahwe: Niech imię Jahwe będzie błogosławione odtąd i aż na wieki.</i>, a kończą słowami: <i>Wysławiajcie Jahwe, bo dobry; bo łaska Jego na wieki!</i>", "H": "<b>H</b> (wymowa: <i>ha</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>h</b><i>;</i> często nazywana też <i>samo ha</i> dla odróżnienia od dwuznaku <b>ch</b>) – ósma litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a>, jedenasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. W języku polskim oznacza głoskę [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_krtaniowa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ɦ</a>] albo [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_mi%C4%99kkopodniebienna_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">x</a>], u przeważającej części użytkowników tę drugą, a w innych językach również [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_krtaniowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">h</a>]. Często jest też niewymawiana (m.in. w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">języku francuskim</a> czy <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">włoskim</a>). W języku polskim ta litera nie jest wymawiana m.in. w wyrazach <a href=\"https://pl.wikipedia.org/wiki/Ghana\" target=\"_blank\" rel=\"noopener noreferrer\">Ghana</a> (wym. <i>Gana</i>) czy <a href=\"https://pl.wikipedia.org/wiki/Thor\" target=\"_blank\" rel=\"noopener noreferrer\">Thor</a> (wym. <i>Tor</i>).", "Hana": "<b>Hana</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;はな, ハナ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Hamam": "<a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">Arabski</a> gramatyk <a href=\"https://pl.wikipedia.org/wiki/Ibn_Sida\" target=\"_blank\" rel=\"noopener noreferrer\">Ibn Sida</a> wywodzi nazwę od słowa <i>al-ḥamīm</i> (\"siła letniego gorąca\").", "Helena": "<b>Helena</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>. Wywodzi się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">stgr.</a>&#160;Ἑλένη oznaczającego „blask Księżyca”. W Polsce po raz pierwszy imię to odnotowano w 1272.", "Humbert": "<b>Humbert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od złożenia słów <i>hun</i> – „wojownik” i <i>beraht</i> – „słynny”. Oryginalnie było imieniem <a href=\"https://pl.wikipedia.org/wiki/Normanowie\" target=\"_blank\" rel=\"noopener noreferrer\">normandzkim</a>. Za pośrednictwem Normandów jego użycie rozszerzyło się na <a href=\"https://pl.wikipedia.org/wiki/Anglia\" target=\"_blank\" rel=\"noopener noreferrer\">Anglię</a> i <a href=\"https://pl.wikipedia.org/wiki/W%C5%82ochy\" target=\"_blank\" rel=\"noopener noreferrer\">Włochy</a>, gdzie nosiło je dwóch królów. Istnieją też święci o tym imieniu.", "Hide": "Liczba łanów wykorzystywana była do określenia wysokości podatków oraz do wyznaczenia powinności wojskowych (<a href=\"https://pl.wikipedia.org/wiki/Fyrd\" target=\"_blank\" rel=\"noopener noreferrer\">fyrd</a>).", "Hulusi": "<b>Hulusi</b> (<a href=\"https://pl.wikipedia.org/wiki/Uproszczone_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. upr.</a> 葫芦丝&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Tradycyjne_pismo_chi%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">chiń. trad.</a> 葫蘆絲&#59;&#32;<a href=\"https://pl.wikipedia.org/wiki/Hanyu_pinyin\" target=\"_blank\" rel=\"noopener noreferrer\">pinyin</a> <i>húlúsī</i>) – tradycyjny chiński dęty instrument muzyczny, popularny wśród mniejszości etnicznych zamieszkujących prowincję <a href=\"https://pl.wikipedia.org/wiki/Junnan\" target=\"_blank\" rel=\"noopener noreferrer\">Junnan</a>, zwłaszcza wśród ludu <a href=\"https://pl.wikipedia.org/wiki/Dai_(mniejszo%C5%9B%C4%87_narodowa)\" target=\"_blank\" rel=\"noopener noreferrer\">Dai</a>. Nazwa instrumentu w języku dai to <i>bilangdao</i>. Nazwa chińska pochodzi od słowa <i>hulu</i> „tykwa” i <i>si</i> „jedwab”, od charakterystycznej miękkiej barwy dźwięku.", "Hanbo": "<b>Hanbō</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;半棒&#32;<i>dosł. <i>półkij</i></i>) – kij długości 3 <a href=\"https://pl.wikipedia.org/wiki/Shaku_(jednostka_miary)\" target=\"_blank\" rel=\"noopener noreferrer\">shaku</a> (około 90 cm). Jego nazwa wywodzi się z tego, że jego długość to połowa długości kija <a href=\"https://pl.wikipedia.org/wiki/B%C5%8D\" target=\"_blank\" rel=\"noopener noreferrer\">rokushakubō</a>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;六尺棒&#32;<i>kij długości 6 shaku</i>).", "Huawei": "<b>Huawei Technologies Co., Ltd.</b> (wymowa, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chiń.</a> 华为技术有限公司) – <a href=\"https://pl.wikipedia.org/wiki/Chi%C5%84ska_Republika_Ludowa\" target=\"_blank\" rel=\"noopener noreferrer\">chiński</a> producent <a href=\"https://pl.wikipedia.org/wiki/Elektronika_u%C5%BCytkowa\" target=\"_blank\" rel=\"noopener noreferrer\">elektroniki użytkowej</a>, <a href=\"https://pl.wikipedia.org/wiki/Sie%C4%87_telekomunikacyjna\" target=\"_blank\" rel=\"noopener noreferrer\">sprzętu telekomunikacyjnego</a>, <a href=\"https://pl.wikipedia.org/wiki/Pojazd_elektryczny\" target=\"_blank\" rel=\"noopener noreferrer\">pojazdów elektrycznych</a>, <a href=\"https://pl.wikipedia.org/wiki/Samoch%C3%B3d_autonomiczny\" target=\"_blank\" rel=\"noopener noreferrer\">samochodów autonomicznych</a> oraz sprzętu i rozwiązań <a href=\"https://pl.wikipedia.org/wiki/Informatyka\" target=\"_blank\" rel=\"noopener noreferrer\">informatycznych</a> założony w 1987 roku, z siedzibą w <a href=\"https://pl.wikipedia.org/wiki/Shenzhen\" target=\"_blank\" rel=\"noopener noreferrer\">Shenzhen</a>.", "Haruka": "<b>Haruka</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;はるか, ハルカ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, noszone częściej przez kobiety niż przez mężczyzn.", "Hilda": "Często bywa zdrobnieniem od imienia Hildegarda, nie jest jednak tożsame z tym imieniem. Odpowiednikiem w języku węgierskim jest Ildikó, w rosyjskim Gilda (Гильда).", "Hidalgo": "<b>Hidalgo</b> – <a href=\"https://pl.wikipedia.org/wiki/Stan_(podzia%C5%82_administracyjny)\" target=\"_blank\" rel=\"noopener noreferrer\">stan</a> położony w środkowym <a href=\"https://pl.wikipedia.org/wiki/Meksyk\" target=\"_blank\" rel=\"noopener noreferrer\">Meksyku</a>. Graniczy ze stanami <a href=\"https://pl.wikipedia.org/wiki/Tlaxcala_(stan)\" target=\"_blank\" rel=\"noopener noreferrer\">Tlaxcala</a>, <a href=\"https://pl.wikipedia.org/wiki/Meksyk_(stan)\" target=\"_blank\" rel=\"noopener noreferrer\">México</a>, <a href=\"https://pl.wikipedia.org/wiki/Quer%C3%A9taro\" target=\"_blank\" rel=\"noopener noreferrer\">Querétaro</a>, <a href=\"https://pl.wikipedia.org/wiki/San_Luis_Potos%C3%AD\" target=\"_blank\" rel=\"noopener noreferrer\">San Luis Potosí</a>, <a href=\"https://pl.wikipedia.org/wiki/Veracruz_(stan)\" target=\"_blank\" rel=\"noopener noreferrer\">Veracruz</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Puebla_(stan)\" target=\"_blank\" rel=\"noopener noreferrer\">Pueblą</a>. Stolicą stanu jest miasto <a href=\"https://pl.wikipedia.org/wiki/Pachuca\" target=\"_blank\" rel=\"noopener noreferrer\">Pachuca</a>. Nazwa stanu pochodzi od przywódcy walk o niepodległość Meksyku – księdza <a href=\"https://pl.wikipedia.org/wiki/Miguel_Hidalgo_y_Costilla\" target=\"_blank\" rel=\"noopener noreferrer\">Miguela Hidalgo y Costilli</a>.", "Heros": "Według greckich wierzeń bogowie często przybywali na ziemię i ingerowali w sprawy ludzi. Zdarzało się, że mieszkańcy <a href=\"https://pl.wikipedia.org/wiki/Olimp\" target=\"_blank\" rel=\"noopener noreferrer\">Olimpu</a> zakochiwali się w śmiertelniczkach, a te wydawały na świat obdarzone boskimi zdolnościami dzieci. Bywały także przypadki, gdy to bogini była matką herosa, a jego ojcem – śmiertelnik. Wyrastały one na bohaterów zwanych herosami. Takie pochodzenie Grecy przypisywali także założycielom miast i prawodawcom, którzy byli postaciami historycznymi. Obecnie pojęcia tego używa się w szerszym znaczeniu przenośnym.", "Himisław": "<b>Imisław</b>, <b>Jimisław</b>, <b>Himisław</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, po raz pierwszy odnotowane w <a href=\"https://pl.wikipedia.org/wiki/1212\" target=\"_blank\" rel=\"noopener noreferrer\">1212</a> roku. Składa się z członów: <i>Imi-</i>, pochodzącego od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">prasł.</a> <i>*jęti</i>, w <a href=\"https://pl.wikipedia.org/wiki/Tryb_rozkazuj%C4%85cy\" target=\"_blank\" rel=\"noopener noreferrer\">trybie rozkazującym</a> <i>*jьmi</i> („jąć”, „rozpocząć”) i <i>-sław</i> („sława”). Nie ma odpowiedników w innych językach słowiańskich. Mogło oznaczać „ten, który zapoczątkowuje sławę”. Jako Himisław (z H-protetycznym) wystąpiło w XV wieku (1409)", "Hortensjusz": "<b>Hortensjusz</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „ogrodnik”. Pochodzi od nazwiska <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">rzymskiego</a> rodu Hortensjuszy. Patronem tego imienia jest św. Hortensjusz, biskup.", "Halina": "<b>Halina</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">gr.</a>&#160;γαλήνη <i>galene</i> – „spokój”, „błogostan”. Od Haliny powstało imię <b>Halka</b>, spopularyzowane dzięki operze <a href=\"https://pl.wikipedia.org/wiki/Stanis%C5%82aw_Moniuszko\" target=\"_blank\" rel=\"noopener noreferrer\">Stanisława Moniuszki</a> – <a href=\"https://pl.wikipedia.org/wiki/Halka_(opera)\" target=\"_blank\" rel=\"noopener noreferrer\">Halka</a>, którą niekiedy nadawano jako samodzielne imię.", "Henryka": "<b>Henryka</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Henryk_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Henryk</a>, o germańskim pochodzeniu.", "Honorata": "<b>Honorata</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Honorat\" target=\"_blank\" rel=\"noopener noreferrer\">Honorat</a>.", "Hildegarda": "<b>Hildegarda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od połączenia słów <i>hild</i> – „bitwa” i <i>gard</i> – ochrona, czyli „ta, która chroni przed wojną”.", "Helga": "<b>Helga</b> – imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Ma pochodzić od staronorweskiego słowa <i>heill</i> oznaczającego <i>szczęśliwa</i> lub <i>ciesząca się pomyślnością</i>.", "Hiacynta": "<b>Hiacynta</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Hiacynt_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Hiacynt</a> o greckim pochodzeniu.", "Halszka": "<b> Halszka</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, powstałe jako zdrobnienie pochodzącego z języka hebrajskiego imienia <a href=\"https://pl.wikipedia.org/wiki/El%C5%BCbieta\" target=\"_blank\" rel=\"noopener noreferrer\">Elżbieta</a>, pochodzące bardziej bezpośrednio od dawnej formy <i>Halżbieta</i> (przez: <i>Halżka</i>).", "Hermina": "<b>Hermina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Herman\" target=\"_blank\" rel=\"noopener noreferrer\">Herman</a>.", "Hieronima": "<b>Hieronima</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Greka\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Hieronim\" target=\"_blank\" rel=\"noopener noreferrer\">Hieronim</a>. Wywodzi się od słów oznaczających \"święta poświęcona bóstwu\" i \"imię\", co można tłumaczyć jako \"nosząca święte imię\".", "Hortensja": "Hortensius była nazwą starorzymskiego rodu Hortensjuszy. Tak więc imię Hortensja oznacza dziewczynę pochodzącą z tego rodu. Nazwa rodu z kolei wywodzona jest od łacińskiego słowa hortus, oznaczającego \"ogród\" (hortensius = ogrodnik). Nazwę rodu niektórzy wywodzą z języka etruskiego, w którym znane było imię Hurtensius.", "Hilaria": "<b>Hilaria</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Hilary\" target=\"_blank\" rel=\"noopener noreferrer\">Hilary</a>. Jego patronką jest św. Hilaria, matka św. <a href=\"https://pl.wikipedia.org/wiki/Afra_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Afry</a>.", "Hermenegilda": "<b>Hermenegilda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o pochodzeniu germańskim. W starogermańskim oznaczało \"pełne poświęcenie\": <i>ermen</i> – 'całe, pełne' i <i>gild</i> – 'poświęcenie'.", "Hatice": "<b>Hatice</b> (ur. ok. <a href=\"https://pl.wikipedia.org/wiki/1494\" target=\"_blank\" rel=\"noopener noreferrer\">1494</a> w <a href=\"https://pl.wikipedia.org/wiki/Edirne\" target=\"_blank\" rel=\"noopener noreferrer\">Edirne</a>, zm. <a href=\"https://pl.wikipedia.org/wiki/2_listopada\" target=\"_blank\" rel=\"noopener noreferrer\">2 listopada</a> <a href=\"https://pl.wikipedia.org/wiki/1538\" target=\"_blank\" rel=\"noopener noreferrer\">1538</a> w <a href=\"https://pl.wikipedia.org/wiki/Stambu%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Stambule</a>) – córka osmańskiego <a href=\"https://pl.wikipedia.org/wiki/Su%C5%82tan\" target=\"_blank\" rel=\"noopener noreferrer\">sułtana</a> <a href=\"https://pl.wikipedia.org/wiki/Selim_I_Gro%C5%BAny\" target=\"_blank\" rel=\"noopener noreferrer\">Selima I</a> i jego żony <a href=\"https://pl.wikipedia.org/wiki/Ay%C5%9Fe_Hafsa\" target=\"_blank\" rel=\"noopener noreferrer\">Ayşe Hafsy</a>, siostra <a href=\"https://pl.wikipedia.org/wiki/Sulejman_Wspania%C5%82y\" target=\"_blank\" rel=\"noopener noreferrer\">Sulejmana Wspaniałego</a>, ciotka sułtana <a href=\"https://pl.wikipedia.org/wiki/Selim_II\" target=\"_blank\" rel=\"noopener noreferrer\">Selima II</a>. Dostała imię na pamiątkę pierwszej żony proroka <a href=\"https://pl.wikipedia.org/wiki/Mahomet\" target=\"_blank\" rel=\"noopener noreferrer\">Mahometa</a>.", "Harriet": "Harriet mogła być jednym z trzech żywych <a href=\"https://pl.wikipedia.org/wiki/%C5%BB%C3%B3%C5%82wie\" target=\"_blank\" rel=\"noopener noreferrer\">żółwi</a>, jakie Darwin w czasie swojego rejsu dookoła świata na okręcie <a href=\"https://pl.wikipedia.org/wiki/HMS_Beagle\" target=\"_blank\" rel=\"noopener noreferrer\">HMS \"Beagle\"</a> pozyskał (raczej nie złapał jej osobiście, gdyż nigdy nie był na <a href=\"https://pl.wikipedia.org/wiki/Santa_Cruz_(Galapagos)\" target=\"_blank\" rel=\"noopener noreferrer\">wyspie Santa Cruz</a>, na której ten <a href=\"https://pl.wikipedia.org/wiki/Podgatunek\" target=\"_blank\" rel=\"noopener noreferrer\">podgatunek</a> żyje) w 1835 na wyspach Galapagos i przywiózł do <a href=\"https://pl.wikipedia.org/wiki/Londyn\" target=\"_blank\" rel=\"noopener noreferrer\">Londynu</a>. W momencie opuszczenia ojczystej wyspy miała około pięciu lat i skorupę o średnicy 11 cali. W 1841 wszystkie trzy żółwie uzyskane od Darwina przewieziono do <a href=\"https://pl.wikipedia.org/wiki/Brisbane\" target=\"_blank\" rel=\"noopener noreferrer\">Brisbane</a> w <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australii</a>. Harriet zamieszkała w miejscowym ogrodzie botanicznym, gdzie przebywała aż do jego likwidacji w 1952. Następnie została umieszczona w miejscowym rezerwacie przyrodniczym, a w latach 60. XX w. znalazła się w <a href=\"https://pl.wikipedia.org/wiki/Ogr%C3%B3d_zoologiczny\" target=\"_blank\" rel=\"noopener noreferrer\">zoo</a>. Wtedy też stwierdzono, że jest samicą i otrzymała żeńskie imię (wcześniej żółw nazywany był Harrym). Ostatnie lata życia, od 1988, spędziła w należącym do <a href=\"https://pl.wikipedia.org/wiki/Steve_Irwin\" target=\"_blank\" rel=\"noopener noreferrer\">Steve'a Irwina</a> <a href=\"https://pl.wikipedia.org/wiki/Australia_Zoo\" target=\"_blank\" rel=\"noopener noreferrer\">Australia Zoo</a> w <a href=\"https://pl.wikipedia.org/wiki/Queensland\" target=\"_blank\" rel=\"noopener noreferrer\">Queensland</a>. Osiągnęła wagę 180 kg i była wielką atrakcją turystyczną całego stanu.", "Hellen": "<b>Hellen</b> (Ἕλλην) – mityczny protoplasta <a href=\"https://pl.wikipedia.org/wiki/Hellenowie_(plemi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Hellenów</a>, późniejszych <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">Greków</a>. Syn <a href=\"https://pl.wikipedia.org/wiki/Deukalion_(syn_Prometeusza)\" target=\"_blank\" rel=\"noopener noreferrer\">Deukaliona</a> (lub czasami <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusa</a>) i <a href=\"https://pl.wikipedia.org/wiki/Pyrra\" target=\"_blank\" rel=\"noopener noreferrer\">Pyrry</a>, brat Amfiktiona i ojciec <a href=\"https://pl.wikipedia.org/wiki/Eol_(syn_Hellena)\" target=\"_blank\" rel=\"noopener noreferrer\">Eola</a>, <a href=\"https://pl.wikipedia.org/wiki/Ksutos\" target=\"_blank\" rel=\"noopener noreferrer\">Ksutosa</a> i <a href=\"https://pl.wikipedia.org/wiki/Doros_(syn_Hellena)\" target=\"_blank\" rel=\"noopener noreferrer\">Dorosa</a>. Z jego imieniem wiąże się nazwa <a href=\"https://pl.wikipedia.org/wiki/Grecy\" target=\"_blank\" rel=\"noopener noreferrer\">Greków</a> (<a href=\"https://pl.wikipedia.org/wiki/Hellenowie\" target=\"_blank\" rel=\"noopener noreferrer\">Hellenowie</a>).", "Hiroko": "<b>Hiroko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひろこ, ヒロコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Heliodora": "<b>Heliodora</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Heliodor_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Heliodor</a>. Wśród patronów — <a href=\"https://pl.wikipedia.org/wiki/B%C5%82ogos%C5%82awiony\" target=\"_blank\" rel=\"noopener noreferrer\">bł.</a> <a href=\"https://pl.wikipedia.org/wiki/Leokadia_Matuszewska\" target=\"_blank\" rel=\"noopener noreferrer\">Maria Heliodora</a> (Leokadia Matuszewska), siostra nazaretanka, wspominana razem z bł. Marią Stellą i innymi towarzyszkami straconymi w Nowogródku 1 sierpnia 1943 roku.", "Huberta": "<b>Huberta</b> – imię żeńskie pochodzenia germańskiego. Jest to żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Hubert\" target=\"_blank\" rel=\"noopener noreferrer\">Hubert</a>.", "Hermiona": "<b>Hermiona</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> (gr. <i>‘Ερμιονη</i>), pochodzące od imienia boga <a href=\"https://pl.wikipedia.org/wiki/Hermes\" target=\"_blank\" rel=\"noopener noreferrer\">Hermesa</a>, znane z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_grecka\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii greckiej</a>, w której <a href=\"https://pl.wikipedia.org/wiki/Hermiona_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Hermiona</a> była córką <a href=\"https://pl.wikipedia.org/wiki/Helena_Troja%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Heleny</a> i <a href=\"https://pl.wikipedia.org/wiki/Menelaos\" target=\"_blank\" rel=\"noopener noreferrer\">Menelaosa</a>. Postać o tym imieniu występuje także w <i><a href=\"https://pl.wikipedia.org/wiki/Zimowa_opowie%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">Zimowej opowieści</a></i> <a href=\"https://pl.wikipedia.org/wiki/William_Szekspir\" target=\"_blank\" rel=\"noopener noreferrer\">Williama Szekspira</a>.", "Hiromi": "<b>Hiromi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひろみ,ヒロミ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety i mężczyzn.", "Hera": "Jej odpowiednikiem w <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a> jest <a href=\"https://pl.wikipedia.org/wiki/Junona\" target=\"_blank\" rel=\"noopener noreferrer\">Junona</a>.", "Hipolita": "<b>Hipolita</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Hipolit_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Hipolit</a>.", "Helle": "Jej ojciec Atamas za namową drugiej żony <a href=\"https://pl.wikipedia.org/wiki/Ino\" target=\"_blank\" rel=\"noopener noreferrer\">Ino</a> postanowił złożyć ją wraz z bratem w ofierze <a href=\"https://pl.wikipedia.org/wiki/Zeus\" target=\"_blank\" rel=\"noopener noreferrer\">Zeusowi</a>. Władca Olimpu niezadowolony jednak z tej ofiary, zesłał skrzydlatego barana o złotym runie, by pomógł dzieciom uciec (według innej wersji przysłała go ich matka), unosząc je w powietrze. Helle nie przeżyła podróży spadając do <a href=\"https://pl.wikipedia.org/wiki/Dardanele\" target=\"_blank\" rel=\"noopener noreferrer\">cieśniny Hellespont</a>, której nazwa miała powstać od jej imienia. Jej brat, który dotarł do <a href=\"https://pl.wikipedia.org/wiki/Kolchida\" target=\"_blank\" rel=\"noopener noreferrer\">Kolchidy</a>, złożył barana w ofierze Zeusowi (jego <a href=\"https://pl.wikipedia.org/wiki/Z%C5%82ote_runo\" target=\"_blank\" rel=\"noopener noreferrer\">złote runo</a> stało się później celem wyprawy <a href=\"https://pl.wikipedia.org/wiki/Argonauci\" target=\"_blank\" rel=\"noopener noreferrer\">Argonautów</a>).", "Hitomi": "<b>Hitomi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひとみ, ヒトミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>", "Hasina": "W <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX wieku</a> termin „hasina” nabrał <a href=\"https://pl.wikipedia.org/wiki/Synekdocha\" target=\"_blank\" rel=\"noopener noreferrer\">synekdochicznie</a> znaczenia <a href=\"https://pl.wikipedia.org/wiki/Danina\" target=\"_blank\" rel=\"noopener noreferrer\">trybutu</a> lub darów składanych władcom, tradycyjnie w formie srebrnej monety i odpowiedniej <a href=\"https://pl.wikipedia.org/wiki/Modlitwa\" target=\"_blank\" rel=\"noopener noreferrer\">modlitwy</a>. Pomimo chrystianizacji wyspy, koncept hasiny do dziś funkcjonuje w kulturze Madagaskaru, a religia chrześcijańska bywa określana mianem „hasiny Europejczyków”.", "Hikari": "<b>Hikari</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひかる, ヒカリ, 光) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>. Oznacza ono światło lub blask.", "Hiltruda": "<b>Hiltruda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające \"z hełmem i siłą\". Były święte katolickie o tym imieniu.", "Homa": "<b>Homa</b> (<a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sans.</a> <b>होम</b>) – w <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmie</a>, <a href=\"https://pl.wikipedia.org/wiki/D%C5%BAinizm\" target=\"_blank\" rel=\"noopener noreferrer\">dźinizmie</a> i <a href=\"https://pl.wikipedia.org/wiki/Buddyzm\" target=\"_blank\" rel=\"noopener noreferrer\">buddyzmie</a> – rodzaj ofiary, której centralnym elementem jest święty <a href=\"https://pl.wikipedia.org/wiki/Ogie%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">ogień</a>. Jest to tradycja bardzo archaiczna, stanowiąca najstarszą formę indyjskiej <a href=\"https://pl.wikipedia.org/wiki/Pud%C5%BAa\" target=\"_blank\" rel=\"noopener noreferrer\">pudźy</a>, prawdopodobnie pochodzenia przedaryjskigo.", "Halia": "Była córką personifikacji morza – <a href=\"https://pl.wikipedia.org/wiki/Pontos\" target=\"_blank\" rel=\"noopener noreferrer\">Pontosa</a> i <a href=\"https://pl.wikipedia.org/wiki/Gaja_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Gai</a> oraz siostrą <a href=\"https://pl.wikipedia.org/wiki/Telchinowie\" target=\"_blank\" rel=\"noopener noreferrer\">Telchinów</a>. Oddawano jej cześć na <a href=\"https://pl.wikipedia.org/wiki/Rodos_(wyspa)\" target=\"_blank\" rel=\"noopener noreferrer\">Rodos</a>. Imię jej pochodzi od słowa αλς, które może oznaczać morze lub sól, jest więc uważana za personifikację słonych wód morskich. Była kochanką <a href=\"https://pl.wikipedia.org/wiki/Posejdon\" target=\"_blank\" rel=\"noopener noreferrer\">Posejdona</a>, z którym miała sześciu synów oraz córkę imieniem Rhode, od której pochodzi nazwa wyspy Rodos.", "Hersylia": "<b>Hersylia</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie o niejasnej etymologii, pochodzące z <a href=\"https://pl.wikipedia.org/wiki/Mitologia_rzymska\" target=\"_blank\" rel=\"noopener noreferrer\">mitologii rzymskiej</a>, w której <a href=\"https://pl.wikipedia.org/wiki/Hersilia\" target=\"_blank\" rel=\"noopener noreferrer\">Hersilia</a> była żoną <a href=\"https://pl.wikipedia.org/wiki/Romulus_i_Remus\" target=\"_blank\" rel=\"noopener noreferrer\">Romulusa</a>. W Polsce imię to nosiła m.in. Hersylia Januszewska, córka ojczyma <a href=\"https://pl.wikipedia.org/wiki/Juliusz_S%C5%82owacki\" target=\"_blank\" rel=\"noopener noreferrer\">Juliusza Słowackiego</a>, <a href=\"https://pl.wikipedia.org/wiki/August_B%C3%A9cu\" target=\"_blank\" rel=\"noopener noreferrer\">Augusta Bécu</a>, która poślubiła wuja Słowackiego, Teofila Januszewskiego (brata <a href=\"https://pl.wikipedia.org/wiki/Salomea_S%C5%82owacka\" target=\"_blank\" rel=\"noopener noreferrer\">Salomei Januszewskiej</a>, matki Słowackiego).", "Hildegunda": "<b>Hildegunda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów <i>hilt(e)a</i> \"<a href=\"https://pl.wikipedia.org/wiki/Bitwa\" target=\"_blank\" rel=\"noopener noreferrer\">bitwa</a>\" oraz <i>gund</i> \"<a href=\"https://pl.wikipedia.org/wiki/Walka_(wojsko)\" target=\"_blank\" rel=\"noopener noreferrer\">walka</a>\", można określić jego pierwotne znaczenie jako \"biorąca udział w bitwie, walce\". Jego zdrobnieniem jest <a href=\"https://pl.wikipedia.org/wiki/Hilda\" target=\"_blank\" rel=\"noopener noreferrer\">Hilda</a>.", "Hermelinda": "<b>Ermelinda</b>, Irmelinda, <i>Hermelinda</i> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, składające się z członów: <i>Ermen–</i>, od germ. <i>ermana</i> („wielki, wszechogarniający” – imię <a href=\"https://pl.wikipedia.org/wiki/P%C3%B3%C5%82b%C3%B3g\" target=\"_blank\" rel=\"noopener noreferrer\">półboga</a> germańskiego) oraz <i>lind</i> – „giętka, miękka, łagodna, przyjazna”, może też „<a href=\"https://pl.wikipedia.org/wiki/Tarcza_(uzbrojenie)\" target=\"_blank\" rel=\"noopener noreferrer\">tarcza</a> z drewna <a href=\"https://pl.wikipedia.org/wiki/Lipa\" target=\"_blank\" rel=\"noopener noreferrer\">lipowego</a>”.", "Hosanna": "Słowo to było okrzykiem powitalnym ludu, który wyszedł na spotkanie <a href=\"https://pl.wikipedia.org/wiki/Jezus\" target=\"_blank\" rel=\"noopener noreferrer\">Jezusowi</a> podczas <a href=\"https://pl.wikipedia.org/wiki/Niedziela_Palmowa#Wjazd_do_Jerozolimy\" target=\"_blank\" rel=\"noopener noreferrer\">wjazdu do Jerozolimy</a>. Wierni, kładąc na drodze płaszcze i gałązki palmowe, wołali: <i>Hosanna! Błogosławiony Ten, który przychodzi w imię Pańskie. Błogosławione królestwo ojca naszego Dawida, które przychodzi. Hosanna na wysokościach!</i> Wydarzenie to miało być spełnieniem słów ze Starego Testamentu: <i>Raduj się wielce, Córo Syjonu, wołaj radośnie, Córo Jeruzalem! Oto Król twój idzie do ciebie, sprawiedliwy i zwycięski. Pokorny – jedzie na osiołku, na oślątku, źrebięciu oślicy</i> (Za 9,9).", "Heta": "<b>Heta</b> (<b>ἧτα</b>, pisana <b>Ͱͱ</b>) – litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu greckiego</a> oznaczająca spółgłoskę [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_szczelinowa_krtaniowa_bezd%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">h</a>], przedstawiająca ją jako pełną literę, a nie tylko jako znak diakrytyczny <a href=\"https://pl.wikipedia.org/wiki/Dasja\" target=\"_blank\" rel=\"noopener noreferrer\">spiritus asper</a> wywodzący się z tej litery, która z kolei wywodzi się z lewej połówki litery <a href=\"https://pl.wikipedia.org/wiki/Eta\" target=\"_blank\" rel=\"noopener noreferrer\">eta</a>.", "Harumi": "<b>Harumi</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;はるみ, ハルミ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Hisako": "<b>Hisako</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ひさこ, ヒサコ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Hanami": "Pełnia kwitnienia (jap. 満開, <i>mankai</i>) następuje zazwyczaj tydzień po otwarciu pierwszych kwiatów (開花, <i>kaika</i>). Po kolejnym tygodniu drzewa zaczynają powoli przekwitać. W Japonii funkcjonuje również wcześniejsza, bardziej starożytna forma <i>hanami</i>, popularna wśród starszych osób, w której obiektem podziwu są kwiaty <a href=\"https://pl.wikipedia.org/wiki/Morela_japo%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">moreli japońskiej</a>, zwanej też śliwą japońską (jap. 梅, <i>ume</i>). Ceremonie te mają spokojniejszy charakter niż często hałaśliwe i zatłoczone imprezy pory kwitnienia wiśni.", "Herma": "Początkowo (do V wieku p.n.e.) forma stosowana w <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytna_Grecja\" target=\"_blank\" rel=\"noopener noreferrer\">Grecji</a> wyłącznie dla przedstawienia <a href=\"https://pl.wikipedia.org/wiki/Hermes\" target=\"_blank\" rel=\"noopener noreferrer\">Hermesa</a>, wraz ze zwyczajowo dodanym wyobrażeniem <a href=\"https://pl.wikipedia.org/wiki/Pr%C4%85cie\" target=\"_blank\" rel=\"noopener noreferrer\">fallusa</a>. Później przedstawiano w ten sposób także innych bogów i herosów. W <a href=\"https://pl.wikipedia.org/wiki/Styl_czarnofigurowy\" target=\"_blank\" rel=\"noopener noreferrer\">czarnofigurowym</a> <a href=\"https://pl.wikipedia.org/wiki/Malarstwo_wazowe\" target=\"_blank\" rel=\"noopener noreferrer\">malarstwie wazowym</a> hermy stanowiły częsty element dekoracyjny. Od IV wieku p.n.e. w tej postaci przedstawiano portrety sławnych ludzi (np. parzysta herma <a href=\"https://pl.wikipedia.org/wiki/Herodot\" target=\"_blank\" rel=\"noopener noreferrer\">Herodota</a> i <a href=\"https://pl.wikipedia.org/wiki/Tukidydes\" target=\"_blank\" rel=\"noopener noreferrer\">Tukidydesa</a>).", "Haruko": "<b>Haruko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;はるこ, ハルコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Hestia": "Każde nowo narodzone dziecko, piątego dnia po urodzeniu, obnoszono dookoła ogniska oddając je Hestii w opiekę. Matka panny młodej rozpalała pierwszy raz ogień w nowym domu płomieniem pochodzącym z jej własnego domu lub ze świętego ogniska. Wyprawiający się w celu założenia nowej kolonii zabierali ogień z tego ogniska dla podtrzymania łączności z ojczyzną. Gość przychodząc do domu, w którym nie był mile widziany, musiał złapać się krawędzi ogniska. Odtąd gospodarze nie mogli mu nic zrobić.", "Hadrianna": "<b>Hadriana</b>, <b>Hadrianna</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Hadrian_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Hadrian</a>.", "Heliana": "Bohaterka ta przybiera w utworze różne postacie cielesne. Najpierw <a href=\"https://pl.wikipedia.org/wiki/Eolion\" target=\"_blank\" rel=\"noopener noreferrer\">Eolion</a> nazywa ją <i>siostrą Atessą</i> i razem wędrują po wszechświecie w somnambulicznym śnie. Gdy kobieta ta umiera, jej matka nazywa ją <i>Helianą</i>. W utworze jest też przedstawiana jako córka rybaka i wtedy nazywana jest <i>Dziewicą</i>. Z kolei w innych fragmentach utworu nazywa się ją imieniem <i>Diana</i>.", "Hsiao": "<b>Nabożność synowska</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_chi%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">chiń.</a>&#160;孝, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#160;こう, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_korea%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">kor.</a>&#160;효) – jedna z najważniejszych cnót w <a href=\"https://pl.wikipedia.org/wiki/Konfucjanizm\" target=\"_blank\" rel=\"noopener noreferrer\">konfucjanizmie</a> oraz innych dalekowschodnich systemach <a href=\"https://pl.wikipedia.org/wiki/Etyka\" target=\"_blank\" rel=\"noopener noreferrer\">etycznych</a>. Jej chińskiej nazwy, <i>xiao</i>, często się nie tłumaczy, bo oznacza ona: <i>miłość, szacunek i posłuszeństwo wobec rodziców, przodków i krewnych</i>. Mimo ogromnych przemian społecznych w <a href=\"https://pl.wikipedia.org/wiki/XX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XX wieku</a>, nabożność synowska jest jedną z wartości wysoko cenionych w <a href=\"https://pl.wikipedia.org/wiki/Chi%C5%84ska_Republika_Ludowa\" target=\"_blank\" rel=\"noopener noreferrer\">Chinach</a>, całej <a href=\"https://pl.wikipedia.org/wiki/Korea\" target=\"_blank\" rel=\"noopener noreferrer\">Korei</a>, <a href=\"https://pl.wikipedia.org/wiki/Japonia\" target=\"_blank\" rel=\"noopener noreferrer\">Japonii</a>, <a href=\"https://pl.wikipedia.org/wiki/Wietnam\" target=\"_blank\" rel=\"noopener noreferrer\">Wietnamie</a>, a także na <a href=\"https://pl.wikipedia.org/wiki/Republika_Chi%C5%84ska\" target=\"_blank\" rel=\"noopener noreferrer\">Tajwanie</a> i w <a href=\"https://pl.wikipedia.org/wiki/Singapur\" target=\"_blank\" rel=\"noopener noreferrer\">Singapurze</a>.", "Hotaru": "<b>Hotaru</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;ほたる, ホタル) – głównie żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, bardzo rzadko noszone przez mężczyzn.", "Hanako": "<b>Hanako</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;はなこ, ハナコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>. Imię popularne było do lat 50. XX wieku. Ostatnio jest coraz rzadziej używane.", "Hiera": "Czy była również matką trzeciego z synów Telefosa, <a href=\"https://pl.wikipedia.org/wiki/Eurypylos_(syn_Telefosa)\" target=\"_blank\" rel=\"noopener noreferrer\">Eurypylosa</a> nie jest do końca jasne. Eurypylos pomścił bowiem pod Troją śmierć Hiery, zabijając Nireusa. Został jednak namówiony do wyprawy pod Troję już po śmierci Telefosa, przez swą matkę, która na dodatek jest nazwana imieniem Astyoche. Możliwe więc, że <a href=\"https://pl.wikipedia.org/wiki/Astyoche_(c%C3%B3rka_Laomedonta)\" target=\"_blank\" rel=\"noopener noreferrer\">Astyoche</a> jest inną żoną Telefosa, córką króla Troi <a href=\"https://pl.wikipedia.org/wiki/Laomedon\" target=\"_blank\" rel=\"noopener noreferrer\">Laomedonta</a>. Czasami z Hierą jest łączony jeszcze inny epizod. Negocjując z Grekami, osiem lat po najeździe na Myzję, w <a href=\"https://pl.wikipedia.org/wiki/Argos_(Grecja)\" target=\"_blank\" rel=\"noopener noreferrer\">Argos</a>, Telefos twierdzi, że nie może ich osobiście poprowadzić pod Troję, ponieważ jego żona, którą nazwał imieniem Laodike, jest córką króla <a href=\"https://pl.wikipedia.org/wiki/Priam\" target=\"_blank\" rel=\"noopener noreferrer\">Priama</a>. Niewykluczone, że mit utożsamił tu żonę Telefosa z Laodike, najpiękniejszą córkę Priama i Hekabe."};
